from collections import deque

def bfs(start, goal, neighbors):
    frontier = deque([start])
    explored = set()

    while frontier:
        node = frontier.popleft()  # FIFO
        if node == goal:
            return True
        explored.add(node)
        for neighbor in neighbors(node):
            if neighbor not in explored:
                frontier.append(neighbor)
    return False
